import axios from "axios";
import React, { useState } from "react";
import { useNavigate } from "react-router-dom";

function Signup()
{
  let [uname, setusername] = useState();
    let [email, setemail] = useState();
    let [password, setpassword] = useState();
    const navigate = useNavigate();
    function handleForm(e) {
        e.preventDefault();
        // console.log(username, email, password);
        //const data = [uname, email, contact,password]
        const data={
            uname:uname,
            email:email,
            password:password
        }
        console.log(data);
        axios({
            method: "post",
            url: "http://localhost/Petshop/signup.php",
            data: data,
            headers: { "Content-Type": "multipart/form-data" },
        }).then(res => {
                console.log(res);
                alert("Record Insert sucessfully");
                navigate(`/Show`);
            })

    }

    return(
        <div>
            <>
  <meta charSet="utf-8" />
  <meta httpEquiv="X-UA-Compatible" content="IE=edge" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <title>Signup</title>
  <link
    rel="stylesheet"
    href="https://maxcdn.bootstrapcdn.com/bootstrap/3.3.7/css/bootstrap.min.css"
  />
  <style
    type="text/css"
    dangerouslySetInnerHTML={{
      __html:
        '\n        body {\n\n\n    background: url("https://res.cloudinary.com/finnhvman/image/upload/v1541930411/pattern.png");\n}\n\t.login-form {\n\t\twidth: 340px;\n    \tmargin: 50px auto;\n        position: relative;\n        top: 120px;\n\t}\n    .login-form form {\n    \tmargin-bottom: 15px;\n        background: #f7f7f7;\n        box-shadow: 0px 2px 2px rgba(0, 0, 0, 0.3);\n        padding: 30px;\n    }\n    .login-form h2 {\n        margin: 0 0 15px;\n    }\n    .form-control, .btn {\n        min-height: 38px;\n        border-radius: 2px;\n    }\n    .btn {\n        font-size: 15px;\n        font-weight: bold;\n    }\n'
    }}
  />
  <div className="login-form">
    <form onSubmit={handleForm}>
      <h2 className="text-center">Signup</h2>
      <div className="form-group">
        <input
          type="text"
          className="form-control"
          name="username"
          placeholder="Username"
          required="required"
          onChange={(e)=>setusername(e.target.value)}
        />
      </div>
      <div className="form-group">
        <input
          type="email"
          className="form-control"
          name="email"
          placeholder="Email"
          required="required"
          onChange={(e)=>setemail(e.target.value)}
        />
      </div>
      <div className="form-group">
        <input
          type="password"
          className="form-control"
          name="password"
          placeholder="Password"
          required="required"
          onChange={(e)=>setpassword(e.target.value)}
        />
      </div>
      <div className="form-group">
        <button type="submit" className="btn btn-primary btn-block">
          Singup
        </button>
      </div>
    </form>
    <p className="text-center">
      <a href="#">Already registered</a>
    </p>
  </div>
</>

        </div>
    )
}
export default Signup;
